function calculateEvenSumAndOddProduct(arr) {
    let evenSum = 0;
    let oddProduct = 1;
    let hasOdd = false;

    for(let i = 0; i < arr.length; i++) {
        if(arr[i] % 2 === 0) {
            // Even number
            evenSum += arr[i];
        } else {
            // Odd number
            oddProduct *= arr[i];
            hasOdd = true;
        }
    }

    console.log(`Array: [${arr}]`);
    console.log(`Sum of even numbers: ${evenSum}`);
    if(hasOdd) {
        console.log(`Product of odd numbers: ${oddProduct}`);
    } else {
        console.log(`Product of odd numbers: No odd numbers found`);
    }
}

// Test the function
const numbers = [2, 5, 8, 3, 10, 7, 4, 9];
calculateEvenSumAndOddProduct(numbers);

// Another test with no odd numbers
const evenNumbers = [2, 4, 6, 8, 10];
calculateEvenSumAndOddProduct(evenNumbers);
```

