// Function to reverse a string
function reverseString(str) {
    return str.split('').reverse().join('');
}

// Function to check if string is palindrome
function isPalindrome(str) {
    // Convert to lowercase and remove non-alphanumeric characters
    const cleanStr = str.toLowerCase().replace(/[^a-z0-9]/g, '');
    const reversed = cleanStr.split('').reverse().join('');
    return cleanStr === reversed;
}

// Alternative manual palindrome check
function isPalindromeManual(str) {
    const cleanStr = str.toLowerCase().replace(/[^a-z0-9]/g, '');
    for(let i = 0; i < cleanStr.length / 2; i++) {
        if(cleanStr[i] !== cleanStr[cleanStr.length - 1 - i]) {
            return false;
        }
    }
    return true;
}

// Test the functions
const testStrings = ["racecar", "hello", "A man a plan a canal Panama", "madam"];

testStrings.forEach(str => {
    console.log(`\nOriginal string: "${str}"`);
    console.log(`Reversed string: "${reverseString(str)}"`);
    console.log(`Is palindrome? ${isPalindrome(str)}`);
    console.log(`Is palindrome (manual)? ${isPalindromeManual(str)}`);
});
```

```javascript
// Student Management System
class StudentManagementSystem {
    constructor() {
        this.students = [];
        this.maxStudents = 100;
    }

    // Add new student
    addStudent(roll, name, marks) {
        // Check if maximum limit reached
        if(this.students.length >= this.maxStudents) {
            console.log("Maximum students limit reached!");
            return false;
        }

        // Check for duplicate roll number
        if(this.students.some(s => s.roll === roll)) {
            console.log(`Student with roll number ${roll} already exists!`);
            return false;
        }

        // Calculate average
        const average = marks.reduce((sum, mark) => sum + mark, 0) / marks.length;

        // Add student
        this.students.push({
            roll: roll,
            name: name,
            marks: marks,
            average: average
        });

        console.log(`Student ${name} added successfully!`);
        return true;
    }

    // Display all students
    displayAllStudents() {
        if(this.students.length === 0) {
            console.log("No students found!");
            return;
        }

        console.log("\n" + "-".repeat(70));
        console.log(`${'Roll No'.padEnd(10)} ${'Name'.padEnd(20)} ${'Sub1'.padEnd(8)} ${'Sub2'.padEnd(8)} ${'Sub3'.padEnd(8)} ${'Average'.padEnd(8)}`);
        console.log("-".repeat(70));

        this.students.forEach(student => {
            console.log(
                `${student.roll.toString().padEnd(10)} ${student.name.padEnd(20)} ` +
                `${student.marks[0].toString().padEnd(8)} ${student.marks[1].toString().padEnd(8)} ` +
                `${student.marks[2].toString().padEnd(8)} ${student.average.toFixed(2).padEnd(8)}`
            );
        });
        console.log("-".repeat(70));
    }

    // Display student averages
    displayStudentAverages() {
        if(this.students.length === 0) {
            console.log("No students found!");
            return;
        }

        console.log("\n" + "-".repeat(40));
        console.log(`${'Roll No'.padEnd(10)} ${'Name'.padEnd(20)} ${'Average'.padEnd(8)}`);
        console.log("-".repeat(40));

        this.students.forEach(student => {
            console.log(
                `${student.roll.toString().padEnd(10)} ${student.name.padEnd(20)} ${student.average.toFixed(2).padEnd(8)}`
            );
        });
        console.log("-".repeat(40));
    }

    // Find topper
    findTopper() {
        if(this.students.length === 0) {
            console.log("No students found!");
            return;
        }

        const topper = this.students.reduce((max, student) => 
            student.average > max.average ? student : max
        );

        console.log("\n" + "=".repeat(30));
        console.log("********** TOPPER **********");
        console.log(`Roll Number: ${topper.roll}`);
        console.log(`Name: ${topper.name}`);
        console.log(`Average Marks: ${topper.average.toFixed(2)}`);
        console.log("=".repeat(30));
    }

    // Sort students by roll number
    sortByRollNumber() {
        if(this.students.length <= 1) return;

        this.students.sort((a, b) => a.roll - b.roll);
        console.log("Students sorted by roll number!");
        this.displayAllStudents();
    }

    // Get student by roll number
    getStudentByRoll(roll) {
        const student = this.students.find(s => s.roll === roll);
        if(student) {
            console.log(`\nStudent found:`);
            console.log(`Roll: ${student.roll}`);
            console.log(`Name: ${student.name}`);
            console.log(`Marks: ${student.marks.join(", ")}`);
            console.log(`Average: ${student.average.toFixed(2)}`);
        } else {
            console.log(`Student with roll number ${roll} not found!`);
        }
        return student;
    }

    // Remove student by roll number
    removeStudent(roll) {
        const index = this.students.findIndex(s => s.roll === roll);
        if(index !== -1) {
            const removed = this.students.splice(index, 1)[0];
            console.log(`Student ${removed.name} removed successfully!`);
        } else {
            console.log(`Student with roll number ${roll} not found!`);
        }
    }

    // Get statistics
    getStatistics() {
        if(this.students.length === 0) {
            console.log("No students found!");
            return;
        }

        const averages = this.students.map(s => s.average);
        const highest = Math.max(...averages);
        const lowest = Math.min(...averages);
        const classAverage = averages.reduce((sum, avg) => sum + avg, 0) / averages.length;

        console.log("\n" + "=".repeat(40));
        console.log("CLASS STATISTICS");
        console.log("=".repeat(40));
        console.log(`Total Students: ${this.students.length}`);
        console.log(`Highest Average: ${highest.toFixed(2)}`);
        console.log(`Lowest Average: ${lowest.toFixed(2)}`);
        console.log(`Class Average: ${classAverage.toFixed(2)}`);
        console.log("=".repeat(40));
    }
}

// ========== DEMONSTRATION ==========

const sms = new StudentManagementSystem();

// Adding students
sms.addStudent(101, "John Doe", [85, 90, 88]);
sms.addStudent(103, "Jane Smith", [92, 89, 94]);
sms.addStudent(102, "Bob Johnson", [78, 82, 80]);
sms.addStudent(105, "Alice Brown", [95, 96, 98]);
sms.addStudent(104, "Charlie Wilson", [70, 75, 72]);

// Display all students
sms.displayAllStudents();

// Display student averages
sms.displayStudentAverages();

// Find topper
sms.findTopper();

// Sort by roll number
console.log("\n--- Sorting by Roll Number ---");
sms.sortByRollNumber();

// Get statistics
sms.getStatistics();

// Search for a student
console.log("\n--- Searching for student ---");
sms.getStudentByRoll(103);

// Remove a student
console.log("\n--- Removing a student ---");
sms.removeStudent(104);

// Display updated list
sms.displayAllStudents();
```
